css:
:host { display: block; }
.hero { background: linear-gradient(135deg, var(--primary), #1a1a2e); padding: 5rem 2rem; text-align: center; min-height: 60vh; display: flex; align-items: center; justify-content: center; }
.content { max-width: 800px; }
h1 { font-size: 3rem; color: white; margin: 0 0 1rem; line-height: 1.1; }
.sub { font-size: 1.25rem; color: rgba(255,255,255,0.8); margin: 0 0 2rem; }
.cta { display: inline-block; padding: 0.875rem 2rem; background: white; color: #1a1a2e; font-weight: 700; border-radius: 8px; text-decoration: none; font-size: 1.1rem; transition: transform 0.2s; }
.cta:hover { transform: translateY(-2px); }
@media (max-width: 768px) { h1 { font-size: 2rem; } .hero { padding: 3rem 1.5rem; } }
